#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
LL T,n,k,f[105],dp[105];
bool vis[105];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL DFS_dp(int u,bool up,bool lst){
    if(u<k)return 1;
    if(!lst&&!up&&dp[u]!=-1)return dp[u];
    LL res=DFS_dp(u-1,up&(!vis[u]),0);
    if(!lst&&(!up||vis[u]))
        res+=DFS_dp(u-1,up,1);
    if(!lst&&!up)dp[u]=res;
    return res;
}
int main(){
    T=read();
    f[1]=1,f[2]=1;
    for(int i=3;i<=90;i++)
        f[i]=f[i-1]+f[i-2];
    while(T--){
        k=read(),n=read()-1;
        LL tmp=n,pp=k;
        memset(vis,0,sizeof(vis));
        memset(dp,-1,sizeof(dp));
        for(int i=90;i>=1;i--)if(f[i]>pp)k=i;
        for(int i=90;i>=1;i--)
            if(tmp>=f[i])tmp-=f[i],vis[i]=1;
        cout<<n-DFS_dp(90,1,0)+1<<"\n";
    }
    return 0;
}
